FALLBACK_CHAIN = [
    "groq",
    "cerebras",
    "mistral",
    "openai",
    "claude",
    "mimo",
]

def _has_key(name):
    keys = {
        "groq": config.GROQ_API_KEY,
        "cerebras": config.CEREBRAS_API_KEY,
        "mistral": config.MISTRAL_API_KEY,
        "openai": config.OPENAI_API_KEY,
        "claude": config.ANTHROPIC_API_KEY,
        "mimo": config.MIMO_API_KEY,
    }
    return bool(keys.get(name))

def get_fallback_provider():
    providers = []
    for name in FALLBACK_CHAIN:
        if _has_key(name):
            try:
                providers.append((name, get_provider(name)))
            except Exception:
                pass
    if not providers:
        raise ValueError("Tidak ada provider dengan API key terkonfigurasi!")
    return providers

class FallbackProvider:
    def __init__(self):
        self._providers = get_fallback_provider()
        self._current_idx = 0
        self.name = self._providers[0][0]
        self.provider = self._providers[0][1]
        self.model = self.provider.model
        self.context_window = self.provider.context_window
        self._fail_counts = {}
        self._MAX_FAILS = 3

    def _next_provider(self):
        self._current_idx = (self._current_idx + 1) % len(self._providers)
        name, prov = self._providers[self._current_idx]
        self.name = name
        self.provider = prov
        self.model = prov.model
        self.context_window = prov.context_window

    def chat(self, messages, tools):
        tried = 0
        total = len(self._providers)
        while tried < total:
            name = self.name
            try:
                result = self.provider.chat(messages, tools)
                self._fail_counts[name] = 0
                return result
            except Exception as e:
                tried += 1
                self._fail_counts[name] = self._fail_counts.get(name, 0) + 1
                err_str = str(e).lower()
                if "429" in err_str or "502" in err_str or "503" in err_str or "529" in err_str:
                    pass
                elif self._fail_counts.get(name, 0) < self._MAX_FAILS:
                    continue
                if tried < total:
                    self._next_provider()
                    continue
                raise
        raise RuntimeError("Semua provider gagal")

